$(".translate-toggle2").click(function(){		
	if ($("#translatediv").hasClass("sdown")){
		$("#translatediv").slideUp();
		$("#translatediv").removeClass("sdown");
	}
	else {
		$("#translatediv").addClass("sdown");
		$("#translatediv").slideDown();
	
	}

});
